/**
 * @summary Get challenge progress summary for both participants
 */
export const getGetChallengeSummaryUrl = (challengeId: number) => {
  return `/api/challenges/${challengeId}/summary`;
};

export const getChallengeSummary = async (
  challengeId: number,
  options?: RequestInit,
): Promise<ChallengeSummary> => {
  return customFetch<ChallengeSummary>(getGetChallengeSummaryUrl(challengeId), {
    ...options,
    method: "GET",
  });
};

export const getGetChallengeSummaryQueryKey = (challengeId: number) => {
  return [`/api/challenges/${challengeId}/summary`] as const;
};

export const getGetChallengeSummaryQueryOptions = <
  TData = Awaited<ReturnType<typeof getChallengeSummary>>,
  TError = ErrorType<unknown>,
>(
  challengeId: number,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getChallengeSummary>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetChallengeSummaryQueryKey(challengeId);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getChallengeSummary>>
  > = ({ signal }) =>
    getChallengeSummary(challengeId, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!challengeId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getChallengeSummary>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetChallengeSummaryQueryResult = NonNullable<
  Awaited<ReturnType<typeof getChallengeSummary>>
>;
export type GetChallengeSummaryQueryError = ErrorType<unknown>;

/**
 * @summary Get challenge progress summary for both participants
 */

export function useGetChallengeSummary<
  TData = Awaited<ReturnType<typeof getChallengeSummary>>,
  TError = ErrorType<unknown>,
>(
  challengeId: number,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getChallengeSummary>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetChallengeSummaryQueryOptions(challengeId, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

/**
 * @summary Get a pre-signed URL for photo upload
 */
export const getGetUploadUrlUrl = (challengeId: number) => {
  return `/api/challenges/${challengeId}/upload-url`;
};

export const getUploadUrl = async (
  challengeId: number,
  uploadUrlBody: UploadUrlBody,
  options?: RequestInit,
): Promise<UploadUrlResponse> => {
  return customFetch<UploadUrlResponse>(getGetUploadUrlUrl(challengeId), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(uploadUrlBody),
  });
};

export const getGetUploadUrlMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof getUploadUrl>>,
    TError,
    { challengeId: number; data: BodyType<UploadUrlBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof getUploadUrl>>,
  TError,
  { challengeId: number; data: BodyType<UploadUrlBody> },
  TContext
> => {
  const mutationKey = ["getUploadUrl"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof getUploadUrl>>,
    { challengeId: number; data: BodyType<UploadUrlBody> }
  > = (props) => {
    const { challengeId, data } = props ?? {};

    return getUploadUrl(challengeId, data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type GetUploadUrlMutationResult = NonNullable<
  Awaited<ReturnType<typeof getUploadUrl>>
>;
export type GetUploadUrlMutationBody = BodyType<UploadUrlBody>;
export type GetUploadUrlMutationError = ErrorType<unknown>;

/**
 * @summary Get a pre-signed URL for photo upload
 */
export const useGetUploadUrl = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof getUploadUrl>>,
    TError,
    { challengeId: number; data: BodyType<UploadUrlBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof getUploadUrl>>,
  TError,
  { challengeId: number; data: BodyType<UploadUrlBody> },
  TContext
> => {
  return useMutation(getGetUploadUrlMutationOptions(options));
};
